				    struct nlattr **attrs)
{
    struct nlattr *link[TIPC_NLA_LINK_MAX + 1];
    struct tipc_link_info link_info;
    int err;

    if (!attrs[TIPC_NLA_LINK])
        return -EINVAL;

    err = nla_parse_nested(link, TIPC_NLA_LINK_MAX, attrs[TIPC_NLA_LINK],
               NULL);
    if (err)
        return err;

    size_t str_len = nla_len(link[TIPC_NLA_LINK_NAME]);
    if (str_len > TIPC_MAX_LINK_NAME) {
        /* truncate the string to the buffer size */
        str_len = TIPC_MAX_LINK_NAME;
    }

    link_info.dest = nla_get_flag(link[TIPC_NLA_LINK_DEST]);
    link_info.up = htonl(nla_get_flag(link[TIPC_NLA_LINK_UP]));
    nla_strlcpy(link_info.str, nla_data(link[TIPC_NLA_LINK_NAME]), str_len);

